// Get transcript segments from WayinVideo response
const segments = $('4. WayinVideo — Get Transcript Results').item.json.data.transcript || [];

if (segments.length === 0) {
  throw new Error('Transcript is empty — check if the video URL is valid and publicly accessible.');
}

// Format transcript with speaker labels and timestamps
const formattedTranscript = segments
  .map(s => {
    const timeInSeconds = Math.floor(s.start / 1000);
    const minutes = Math.floor(timeInSeconds / 60);
    const seconds = timeInSeconds % 60;
    const timestamp = `${minutes}:${seconds.toString().padStart(2, '0')}`;
    return `[${s.speaker} | ${timestamp}] ${s.text.trim()}`;
  })
  .join('\n');

// Calculate total duration
const lastSegment = segments[segments.length - 1];
const totalDurationMs = lastSegment?.end || 0;
const totalMinutes = Math.round(totalDurationMs / 60000);

// Count unique speakers
const speakers = [...new Set(segments.map(s => s.speaker))];

// Word count
const wordCount = segments.map(s => s.text).join(' ').split(/\s+/).length;

return [{
  json: {
    formattedTranscript,
    wordCount,
    totalMinutes,
    speakerCount: speakers.length,
    speakers: speakers.join(', '),
    episodeTitle: $('1. Form — Podcast URL + Details').item.json['Episode Title'],
    hostGuestName: $('1. Form — Podcast URL + Details').item.json['Host / Guest Name'],
    targetAudience: $('1. Form — Podcast URL + Details').item.json['Target Audience'],
    linkedinTone: $('1. Form — Podcast URL + Details').item.json['Your LinkedIn Tone'] || 'Professional and insightful',
    videoUrl: $('1. Form — Podcast URL + Details').item.json['Podcast / Episode Video URL']
  }
}];

// Parse the AI output into structured fields
const output = $input.first().json.output || '';

// Extract HEADLINE
const headlineMatch = output.match(/HEADLINE:\s*([\s\S]*?)(?=\nARTICLE:|$)/);
const headline = headlineMatch ? headlineMatch[1].trim() : 'LinkedIn Newsletter Draft';

// Extract ARTICLE
const articleMatch = output.match(/ARTICLE:\s*([\s\S]*?)(?=\nKEY TAKEAWAYS:|$)/);
const article = articleMatch ? articleMatch[1].trim() : output;

// Extract KEY TAKEAWAYS
const takeawaysMatch = output.match(/KEY TAKEAWAYS:\s*([\s\S]*?)(?=\nHASHTAGS:|$)/);
const keyTakeaways = takeawaysMatch ? takeawaysMatch[1].trim() : '';

// Extract HASHTAGS
const hashtagsMatch = output.match(/HASHTAGS:\s*([\s\S]*)$/);
const hashtags = hashtagsMatch ? hashtagsMatch[1].trim() : '';

// Word count of final article
const wordCount = article.split(/\s+/).length;

return [{
  json: {
    headline,
    article,
    keyTakeaways,
    hashtags,
    wordCount,
    episodeTitle: $('7. Code — Format Transcript').item.json.episodeTitle,
    videoUrl: $('7. Code — Format Transcript').item.json.videoUrl,
    totalMinutes: $('7. Code — Format Transcript').item.json.totalMinutes
  }
}];
